15	    expect(calculatePremium([{ type: "Staff" }])).toBe(85);
16	  });
17	  it("should return 45 G for a single potion (40 G base + 5 G fee)", () => {
18	    expect(calculatePremium([{ type: "Potion" }])).toBe(45);
19	  });
20	  it("should sum base premiums for two different items (sword 100 + amulet 60 = 160 base + 5 fee = 165)", () => {
21	    expect(calculatePremium([{ type: "Sword" }, { type: "Amulet" }])).toBe(165);
22	  });
23	  it("should sum base premiums for three different items (sword 100 + amulet 60 + staff 80 = 240 base + 5 fee = 245)", () => {
24	    expect(calculatePremium([{ type: "Sword" }, { type: "Amulet" }, { type: "Staff" }])).toBe(245);
25	  });
26	  it("should apply 50% cursed surcharge to item base premium (sword 100 base + 50 cursed = 150 total item premium + 5 fee = 155)", () => {
