28	  });
29	  it("should apply 30% high-enchantment surcharge for enchantment >= 5 (sword 100 base + 30 surcharge = 130 item premium + 5 fee = 135)", () => {
30	    expect(calculatePremium([{ type: "Sword", enchantment: 5 }])).toBe(135);
31	  });
32	  it("should apply 20% loyalty discount for customers with >= 2 years (policy base 160 G with 2-year customer: 160 - 32 = 128 + 5 fee = 133)", () => {
33	    expect(calculatePremium([{ type: "Sword" }, { type: "Amulet" }], { yearsAsCustomer: 2 })).toBe(133);
34	  });
35	  it("should apply 10% first insurance surcharge for customers with 0 years (policy base 100 G: 100 + 10 = 110 + 5 fee = 115)", () => {
36	    expect(calculatePremium([{ type: "Sword" }], { yearsAsCustomer: 0 })).toBe(115);
37	  });
38	  it("should apply 15% follow-up contract discount for customers' 2nd+ quote (policy base 100 G with 2nd quote: 100 - 15 = 85 + 5 fee = 90)", () => {
39	    expect(calculatePremium([{ type: "Sword" }], { yearsAsCustomer: 1, isFollowUpQuote: true })).toBe(90);
40	  });
41	  it("should add 5 G processing fee at the end", () => {
42	    // Verify fee is added after all calculations
43	    const processingFeeOnlyResult = calculatePremium([]);
44	    expect(processingFeeOnlyResult).toBe(5);
45	  });
46	  it("should round up final premium in MHPCO's favor (197.5 G rounds up to 198 G)", () => {
47	    expect(calculatePremium([{ type: "Potion", cursed: true }], { yearsAsCustomer: 1, isFollowUpQuote: true })).toBe(198);
48	  });
49	  it("should handle multiple items with different modifiers (sword cursed 100+50=150, amulet plain 60, staff enchanted 80+24=104: total 314 base + 5 fee)", () => {
50	    expect(calculatePremium([
51	      { type: "Sword", cursed: true },
52	      { type: "Amulet" },
53	      { type: "Staff", enchantment: 5 }
54	    ])).toBe(319);
55	  });
56	  it("should reject quote with unknown item type", () => {
57	    expect(() => calculatePremium([{ type: "UnknownItem" }])).toThrow();
